// Calcule un offset déterministe basé sur la date du jour
// pour parcourir le dataset sans répéter les mêmes pages
const today = new Date();
const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate();
const offset = (seed % 50) * 20; // 0 à 980, couvre jusqu'à 1000 entrées
const page = Math.floor(offset / 20) + 1;
return [{ json: { offset, page, date: today.toISOString().split('T')[0] } }];

// Blacklist : chaînes, fast-food, grandes surfaces, hôpitaux
const BLACKLIST = [
  'STARBUCKS', 'COLUMBUS', 'MCDONALD', 'CAFETERIA', 'CASINO',
  'MONOPRIX', 'FRANPRIX', 'CARREFOUR', 'LECLERC', 'RELAY',
  'HOPITAL', 'EHPAD', 'WOK', 'SUSHI', 'PIZZA', 'BURGER', 'KEBAB',
  'SUBWAY', 'QUICK', 'KFC', 'FLUNCH', 'COURTEPAILLE', 'HIPPOPOTAMUS',
  'PLANET', 'DOMINO', 'FIVE GUYS', 'LEON', 'COJEAN', 'RAMEN'
];

// Whitelist activité : établissements susceptibles d'acheter du café specialty
const WHITELIST_ACTIVITE = [
  'caf', 'coffee', 'torréf', 'salon de thé', 'tea room',
  'barista', 'brûlerie', 'brulerie', 'espresso', 'brunch', 'restaur',
  'brasserie', 'bistro', 'bar', 'hôtel', 'hotel', 'epicerie', 'épicerie'
];

const all = $input.all();
const seen = new Set();
const result = [];

for (const item of all) {
  // Le tabular API data.gouv retourne les enregistrements dans "data"
  const records = item.json?.data || item.json?.results || [];

  for (const r of records) {
    const name     = (r.APP_Libelle_etablissement || '').trim();
    const activite = (r.APP_Libelle_activite_etablissement || '').toLowerCase();
    // Adresse_2_UA est le champ adresse du dataset Alim'confiance
    // On garde un fallback sur Adresse_etablissement si absent
    const adresse  = (r.Adresse_2_UA || r.Adresse_etablissement || '').trim();
    const cp       = (r.Code_postal || '').toString().trim();
    const commune  = (r.Libelle_commune || '').trim();
    const siret    = (r.SIRET || '').toString().trim();
    const dep      = (r.dep_code || '').toString().trim();
    const note     = (r.Synthese_eval_sanit || '');

    // Filtres d'exclusion
    if (!name || name.length < 3) continue;
    if (dep !== '75') continue; // Sécurité, même si l'URL filtre déjà
    if (note === 'A améliorer') continue; // Mauvaise note sanitaire

    const nameUp = name.toUpperCase();
    if (BLACKLIST.some(b => nameUp.includes(b))) continue;

    // Au moins une activité doit correspondre à la whitelist
    const activiteOK = WHITELIST_ACTIVITE.some(w => activite.includes(w));
    if (!activiteOK) continue;

    // Déduplication intra-batch sur les 10 premiers caractères alphanum du nom
    const key = nameUp.replace(/[^A-Z0-9]/g, '').substring(0, 10);
    if (seen.has(key)) continue;
    seen.add(key);

    result.push({
      nom: name,
      adresse,
      code_postal: cp,
      commune,
      activite: r.APP_Libelle_activite_etablissement || '',
      siret,
      dep,
      key
    });
  }
}

console.log('Résultats après filtre:', result.length);

if (result.length === 0) {
  return [{ json: { _skip: true } }];
}

return result.slice(0, 15).map(r => ({ json: r }));

// Sépare les candidats (issus de Filtrer, ont un champ 'key')
// des données Notion (réponse API, ont un champ 'results')
const allItems = $input.all();
const candidats    = allItems.filter(i => i.json.key);
const notionItems  = allItems.filter(i => !i.json.key);

// Construit le Set des noms déjà présents dans Notion
const existing = new Set();
for (const item of notionItems) {
  const results = item.json?.results || [];
  for (const r of results) {
    const t = r.properties?.Nom?.title?.[0]?.plain_text || '';
    if (t) {
      existing.add(t.toUpperCase().replace(/[^A-Z0-9]/g, '').substring(0, 10));
    }
  }
}

// Garde uniquement les candidats absents de Notion
const seen     = new Set();
const nouveaux = [];
for (const item of candidats) {
  const k = item.json.key;
  if (!existing.has(k) && !seen.has(k)) {
    seen.add(k);
    nouveaux.push({ json: item.json });
  }
}

console.log('Nouveaux prospects:', nouveaux.length);

if (nouveaux.length === 0) {
  return [{ json: { _skip: true } }];
}

return nouveaux.slice(0, 10);

// Récupère la réponse IA et les données du prospect
const aiResponse = $('OpenRouter — Mistral').item.json;
const text = aiResponse?.choices?.[0]?.message?.content || '';

// Parse l'objet et le corps du mail
const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
let objet = '';
const bodyLines = [];
let headerParsed = false;

for (const line of lines) {
  if (!headerParsed && /^objet\s*:/i.test(line)) {
    objet = line.replace(/^objet\s*:\s*/i, '').trim();
    headerParsed = true;
  } else if (headerParsed) {
    bodyLines.push(line);
  }
}

// Fallback si l'IA n'a pas respecté le format
if (!objet) {
  objet = 'Café éthiopien pour votre établissement';
  bodyLines.push(...lines);
}

// Données du prospect (item courant = issu de Anti-doublons via OpenRouter)
const p = $('Anti-doublons').item.json;
const adresseComplete = [
  p.adresse || '',
  p.code_postal || '',
  p.commune || ''
].filter(Boolean).join(', ').substring(0, 200);

const notes = [
  p.siret ? 'SIRET: ' + p.siret : '',
  p.activite || '',
  p.dep ? 'Dep: ' + p.dep : ''
].filter(Boolean).join(' | ').substring(0, 200);

// Construit le body Notion comme objet (pas de stringify ici)
const notionBody = {
  parent: { database_id: '8aa6d741-7872-47d0-94b9-6ac4bc8039f6' },
  properties: {
    'Nom': {
      title: [{ text: { content: (p.nom || '').substring(0, 100) } }]
    },
    'Adresse': {
      rich_text: [{ text: { content: adresseComplete } }]
    },
    'Catégorie': {
      select: { name: 'Cool & Trendy' }
    },
    'Score Pertinence': {
      number: 7
    },
    'Statut Email': {
      select: { name: 'À envoyer' }
    },
    'Notes': {
      rich_text: [{ text: { content: notes } }]
    }
  },
  children: [
    {
      object: 'block',
      type: 'callout',
      callout: {
        rich_text: [{
          type: 'text',
          text: { content: ('Objet : ' + objet).substring(0, 200) }
        }],
        icon: { emoji: '📧' },
        color: 'blue_background'
      }
    },
    {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [{
          type: 'text',
          text: { content: bodyLines.join('\n').substring(0, 2000) }
        }]
      }
    }
  ]
};

return [{ json: { notionBody } }];
